+    private <T> T implementInterface(Class<T> iface) {
+        return iface.cast(Proxy.newProxyInstance(iface.getClassLoader(),
+                new Class[]{iface},
+                (proxy, method, args) -> {
+                    if (args == null) {
+                        args = new Object[0];
+                    }
